const portales = [
  {
    id: 'wallapop',
    nombre: 'Wallapop',
    tipo: 'json_api',
    url: 'https://api.wallapop.com/api/v3/general/search?source=quick_filters&keywords=coche&category_ids=100&order_by=newest&start=0&step=40',
    method: 'GET',
    headers: { 'User-Agent': 'Mozilla/5.0', 'Accept': 'application/json' },
    json_items_path: 'data.section.payload.items',
    json_map: { titulo: 'content.title', precio: 'content.price', km: 'content.km', year: 'content.year', lugar: 'content.location.city', id_externo: 'id', link_base: 'https://es.wallapop.com/item/' }
  },
  {
    id: 'milanuncios',
    nombre: 'Milanuncios',
    tipo: 'json_api',
    url: 'https://www.milanuncios.com/api/v1/listing?cg=2800&ord=date&numPage=1&numItems=40',
    method: 'GET',
    headers: { 'User-Agent': 'Mozilla/5.0', 'Accept': 'application/json' },
    json_items_path: 'items',
    json_map: { titulo: 'title', precio: 'price', km: 'km', year: 'year', lugar: 'province', id_externo: 'id', link_base: 'https://www.milanuncios.com' }
  }
];
return portales.map(p => ({ json: p }));

const portal = $input.all()[0].json;
const respuesta = $input.all()[0].json.data || $input.all()[0].json;
const fechaSync = new Date().toISOString();
const resultados = [];

if (!respuesta) return [];

let items = [];
try {
  const path = (portal.json_items_path || '').split('.');
  let cursor = typeof respuesta === 'string' ? JSON.parse(respuesta) : respuesta;
  for (const key of path) { cursor = cursor?.[key]; if (!cursor) break; }
  items = Array.isArray(cursor) ? cursor : [];
} catch(e) { return []; }

for (const item of items.slice(0, 30)) {
  const get = (obj, path) => { if (!path) return ''; return path.split('.').reduce((o, k) => o?.[k], obj) ?? ''; };
  const map = portal.json_map || {};
  const titulo = get(item, map.titulo) || '';
  const precio = parseFloat(String(get(item, map.precio) || 0).replace(/[^0-9.]/g,'')) || 0;
  if (!titulo || precio === 0) continue;

  resultados.push({
    json: {
      portal_id: portal.id,
      portal: portal.nombre,
      titulo: titulo.substring(0, 250),
      precio,
      km: parseInt(get(item, map.km)) || 0,
      year: String(get(item, map.year) || '').substring(0, 10),
      lugar: String(get(item, map.lugar) || '').substring(0, 100),
      link: (map.link_base || '') + String(get(item, map.id_externo) || ''),
      id_unico: `${portal.id}_${get(item, map.id_externo)}`,
      fecha_sync: fechaSync,
      es_nuevo: true
    }
  });
}

return resultados.length > 0 ? resultados : [];

const portales = $('📈 Resumen').all();
const baratos = $('🏆 Top 5').all();
const hoy = new Date().toLocaleDateString('es-ES');
let tabla = '<table style="width:100%; border-collapse: collapse;"><tr><th style="border:1px solid #ccc; padding: 10px;">Portal</th><th style="border:1px solid #ccc; padding: 10px;">Nuevos</th><th style="border:1px solid #ccc; padding: 10px;">Min</th><th style="border:1px solid #ccc; padding: 10px;">Media</th></tr>';
for (const p of portales) {
  tabla += `<tr><td style="border:1px solid #ccc; padding: 10px;">${p.json.portal}</td><td style="border:1px solid #ccc; padding: 10px;">${p.json.nuevos}</td><td style="border:1px solid #ccc; padding: 10px;">€${p.json.min_precio}</td><td style="border:1px solid #ccc; padding: 10px;">€${p.json.avg_precio}</td></tr>`;
}
tabla += '</table><br>';
let chollos = '<h3>Top 5 Chollos</h3><ul>';
for (const c of baratos) {
  chollos += `<li>${c.json.titulo} - €${c.json.precio} (${c.json.portal})</li>`;
}
chollos += '</ul>';
const html = `<h1>AutoRadar - ${hoy}</h1><h2>Resumen diario</h2>${tabla}${chollos}<p>Dashboard: <a href="https://autoradar-dashboard.vercel.app">https://autoradar-dashboard.vercel.app</a></p>`;
return [{ json: { html, asunto: `AutoRadar - Reporte ${hoy}` } }];
